INSERT INTO problem (owner_user_id, subject_id, unit_id, question_text, choices, correct_choice_key, created_at, updated_at) VALUES
(1, 1, 1, '컴퓨터 시스템의 하드웨어와 소프트웨어에 대한 설명으로 옳은 것은?', '[{"key":"①","text":"하드웨어는 CPU, 메모리, 입출력장치로 구성된다"},{"key":"②","text":"소프트웨어만으로 컴퓨터를 구동할 수 있다"},{"key":"③","text":"펌웨어는 소프트웨어가 아니다"},{"key":"④","text":"시스템 소프트웨어에는 스프레드시트가 포함된다"}]', '①', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
(1, 1, 1, '시스템 소프트웨어에 해당하는 것은?', '[{"key":"①","text":"워드프로세서"},{"key":"②","text":"운영체제"},{"key":"③","text":"게임"},{"key":"④","text":"웹 브라우저"}]', '②', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
(1, 1, 1, '컴퓨터 발전 과정에서 3세대 컴퓨터의 특징은?', '[{"key":"①","text":"진공관 사용"},{"key":"②","text":"트랜지스터 사용"},{"key":"③","text":"집적회로(IC) 사용"},{"key":"④","text":"초대규모 집적회로 사용"}]', '③', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
(1, 1, 1, '하드웨어 구성 요소가 아닌 것은?', '[{"key":"①","text":"중앙처리장치"},{"key":"②","text":"기억장치"},{"key":"③","text":"컴파일러"},{"key":"④","text":"입출력장치"}]', '③', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
(1, 1, 1, '소프트웨어의 분류로 적절하지 않은 것은?', '[{"key":"①","text":"시스템 소프트웨어"},{"key":"②","text":"응용 소프트웨어"},{"key":"③","text":"유틸리티 소프트웨어"},{"key":"④","text":"하드웨어 소프트웨어"}]', '④', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
(1, 1, 2, '2진수 1010을 10진수로 변환하면?', '[{"key":"①","text":"8"},{"key":"②","text":"9"},{"key":"③","text":"10"},{"key":"④","text":"11"}]', '③', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
(1, 1, 2, '부울 대수에서 A + 1의 결과는?', '[{"key":"①","text":"0"},{"key":"②","text":"1"},{"key":"③","text":"A"},{"key":"④","text":"A''"}]', '②', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
(1, 1, 2, '보수 표현에서 2의 보수에 대한 설명으로 옳은 것은?', '[{"key":"①","text":"양수와 음수를 같은 방식으로 표현한다"},{"key":"②","text":"1의 보수에 1을 더한 것이다"},{"key":"③","text":"부호화 절대값과 같다"},{"key":"④","text":"가장 작은 비트만 부호 비트로 쓴다"}]', '②', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
(1, 1, 2, 'BCD 코드에 대한 설명으로 옳은 것은?', '[{"key":"①","text":"4비트로 16가지 상태를 표현한다"},{"key":"②","text":"10진수 한 자리를 4비트 2진수로 표현한다"},{"key":"③","text":"ASCII 코드와 동일하다"},{"key":"④","text":"한 바이트에 3자리 10진수를 넣는다"}]', '②', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
(1, 1, 2, 'AND 게이트의 출력이 1이 되기 위한 입력 조건은?', '[{"key":"①","text":"입력 중 하나만 1"},{"key":"②","text":"모든 입력이 1"},{"key":"③","text":"모든 입력이 0"},{"key":"④","text":"입력의 개수가 짝수"}]', '②', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
(1, 1, 3, '카르노맵의 활용 목적으로 가장 적절한 것은?', '[{"key":"①","text":"논리 회로의 시뮬레이션"},{"key":"②","text":"논리식의 간소화"},{"key":"③","text":"진리표 작성"},{"key":"④","text":"카운터 설계"}]', '②', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
(1, 1, 3, '조합 논리 회로에 해당하는 것은?', '[{"key":"①","text":"플립플롭"},{"key":"②","text":"멀티플렉서"},{"key":"③","text":"카운터"},{"key":"④","text":"레지스터"}]', '②', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
(1, 1, 3, '순서 논리 회로의 특징은?', '[{"key":"①","text":"입력만으로 출력이 결정된다"},{"key":"②","text":"과거 상태를 기억한다"},{"key":"③","text":"비동기적으로 동작한다"},{"key":"④","text":"조합 회로와 동일하다"}]', '②', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
(1, 1, 3, '반가산기의 입력이 A=1, B=1일 때 합(S)과 자리올림(C)은?', '[{"key":"①","text":"S=0, C=0"},{"key":"②","text":"S=0, C=1"},{"key":"③","text":"S=1, C=0"},{"key":"④","text":"S=1, C=1"}]', '②', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
(1, 1, 3, '디코더의 기능은?', '[{"key":"①","text":"여러 입력 중 하나를 선택"},{"key":"②","text":"n비트 입력을 2^n개 출력으로 변환"},{"key":"③","text":"두 수를 더함"},{"key":"④","text":"데이터를 저장"}]', '②', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
(1, 1, 4, 'CPU의 주요 구성 요소가 아닌 것은?', '[{"key":"①","text":"산술논리연산장치(ALU)"},{"key":"②","text":"제어장치"},{"key":"③","text":"레지스터"},{"key":"④","text":"캐시 디렉터리"}]', '④', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
(1, 1, 4, '누산기(Accumulator)의 역할은?', '[{"key":"①","text":"명령어를 해석한다"},{"key":"②","text":"연산 결과를 일시 저장한다"},{"key":"③","text":"다음 명령 주소를 저장한다"},{"key":"④","text":"입출력을 제어한다"}]', '②', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
(1, 1, 4, '메이저 스테이트에 포함되지 않는 것은?', '[{"key":"①","text":"인출(Fetch)"},{"key":"②","text":"간접(Indirect)"},{"key":"③","text":"실행(Execute)"},{"key":"④","text":"저장(Store)"}]', '④', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
(1, 1, 4, '제어장치의 기능은?', '[{"key":"①","text":"산술 연산 수행"},{"key":"②","text":"명령어 해석 및 제어 신호 발생"},{"key":"③","text":"데이터 저장"},{"key":"④","text":"주소 계산"}]', '②', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
(1, 1, 4, '프로그램 카운터(PC)가 저장하는 것은?', '[{"key":"①","text":"현재 실행 중인 명령어"},{"key":"②","text":"다음에 인출할 명령어의 주소"},{"key":"③","text":"연산 결과"},{"key":"④","text":"오퍼랜드"}]', '②', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
(1, 1, 5, '마이크로 오퍼레이션에 대한 설명으로 옳은 것은?', '[{"key":"①","text":"여러 명령어를 동시에 실행한다"},{"key":"②","text":"CPU 내부의 기본 동작 단위이다"},{"key":"③","text":"메모리 접근만을 의미한다"},{"key":"④","text":"입출력 전용 연산이다"}]', '②', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
(1, 1, 5, '즉시 주소 지정 방식의 특징은?', '[{"key":"①","text":"오퍼랜드가 유효주소이다"},{"key":"②","text":"오퍼랜드가 주소를 가리킨다"},{"key":"③","text":"오퍼랜드가 레지스터 번호이다"},{"key":"④","text":"오퍼랜드가 상대주소이다"}]', '①', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
(1, 1, 5, '직접 주소 지정에서 오퍼랜드는?', '[{"key":"①","text":"실제 데이터"},{"key":"②","text":"유효 주소"},{"key":"③","text":"레지스터 번호"},{"key":"④","text":"명령어 개수"}]', '②', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
(1, 1, 5, '간접 주소 지정의 장점은?', '[{"key":"①","text":"주소 공간 확장"},{"key":"②","text":"실행 속도 향상"},{"key":"③","text":"명령어 길이 감소"},{"key":"④","text":"캐시 적중률 향상"}]', '①', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
(1, 1, 5, '인덱스 레지스터를 사용하는 주소 지정 방식은?', '[{"key":"①","text":"즉시"},{"key":"②","text":"직접"},{"key":"③","text":"인덱스"},{"key":"④","text":"묵시적"}]', '③', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
